import { useEffect, useRef, useState, useCallback } from 'react';
import { io } from 'socket.io-client';

const SERVER_URL =
  import.meta.env.VITE_BACKEND_URL ||
  "http://localhost:5000"; // fallback to localhost for development

console.log("Connecting to:", SERVER_URL);

export function useSocket() {
  const socketRef = useRef(null);
  const [connected, setConnected] = useState(false);
  const [identity, setIdentity] = useState(null);       // { avatar, name }
  const [messages, setMessages] = useState([]);
  const [soulCount, setSoulCount] = useState(0);
  const [typingUsers, setTypingUsers] = useState({});   // { id: { name, avatar } }

  // New States
  const [currentRoom, setCurrentRoom] = useState('lobby');
  const [matchStatus, setMatchStatus] = useState('idle'); // 'idle', 'searching', 'paired'
  const [partner, setPartner] = useState(null);           // { name, avatar }

  // Voice Chat States
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [isPartnerVoiceActive, setIsPartnerVoiceActive] = useState(false);
  const [localStream, setLocalStream] = useState(null);
  const [remoteStream, setRemoteStream] = useState(null);

  // Admin States
  const [isAdmin, setIsAdmin] = useState(false);
  const [adminUsers, setAdminUsers] = useState([]);
  const [adminBans, setAdminBans] = useState([]);
  const [adminError, setAdminError] = useState(null);

  // Ban States
  const [isBanned, setIsBanned] = useState(false);
  const [banReason, setBanReason] = useState('');

  // Refs for WebRTC
  const pcRef = useRef(null);
  const localStreamRef = useRef(null);

  // Retrieve or generate persistent deviceId
  const deviceId = useRef(null);
  if (!deviceId.current) {
    let id = localStorage.getItem('void_device_id');
    if (!id) {
      id = 'void_dev_' + Math.random().toString(36).substring(2, 9) + '_' + Date.now();
      localStorage.setItem('void_device_id', id);
    }
    deviceId.current = id;
  }

  // Clean WebRTC Connection helper
  const closePeerConnection = useCallback(() => {
    if (pcRef.current) {
      pcRef.current.close();
      pcRef.current = null;
    }
    if (localStreamRef.current) {
      localStreamRef.current.getTracks().forEach((track) => track.stop());
      localStreamRef.current = null;
      setLocalStream(null);
    }
    setRemoteStream(null);
    setIsVoiceActive(false);
    setIsPartnerVoiceActive(false);
  }, []);

  useEffect(() => {
    const socket = io(SERVER_URL, {
      transports: ['websocket', 'polling'],
      reconnectionAttempts: 10,
      reconnectionDelay: 1500,
      query: { deviceId: deviceId.current }
    });
    socketRef.current = socket;

    socket.on('connect', () => setConnected(true));
    socket.on('disconnect', () => {
      setConnected(false);
      closePeerConnection();
    });
    socket.on('connect_error', () => setConnected(false));

    socket.on('your-identity', (data) => {
      setIdentity(data);
    });

    socket.on('history', (msgs) => {
      setMessages(msgs);
    });

    socket.on('receive-message', (msg) => {
      setMessages((prev) => [...prev, msg]);
    });

    socket.on('system-message', (msg) => {
      setMessages((prev) => [...prev, { ...msg, isSystem: true }]);
    });

    socket.on('soul-count', (count) => {
      setSoulCount(count);
    });

    socket.on('user-typing', ({ id, name, avatar }) => {
      setTypingUsers((prev) => ({ ...prev, [id]: { name, avatar } }));
    });

    socket.on('user-stopped-typing', (id) => {
      setTypingUsers((prev) => {
        const next = { ...prev };
        delete next[id];
        return next;
      });
    });

    socket.on('rate-limited', ({ message }) => {
      setMessages((prev) => [
        ...prev,
        { id: 'rl_' + Date.now(), isSystem: true, text: message, ts: Date.now() },
      ]);
    });

    socket.on('report-received', ({ message }) => {
      setMessages((prev) => [
        ...prev,
        { id: 'rep_' + Date.now(), isSystem: true, text: message, ts: Date.now() },
      ]);
    });

    // ── Reactions Events ────────────────────────────────
    socket.on('message-reaction-updated', ({ messageId, reactions }) => {
      setMessages((prev) =>
        prev.map((msg) => (msg.id === messageId ? { ...msg, reactions } : msg))
      );
    });

    // ── Matchmaking Events ──────────────────────────────
    socket.on('matchmaking-status', (status) => {
      if (status === 'searching') {
        setMatchStatus('searching');
        setPartner(null);
        setMessages([]);
      } else if (status === 'idle') {
        setMatchStatus('idle');
        setPartner(null);
      }
    });

    socket.on('match-paired', ({ partner: partnerData }) => {
      setMatchStatus('paired');
      setPartner(partnerData);
      setMessages([]);
      closePeerConnection(); // Reset voice state just in case
    });

    socket.on('match-unpaired', ({ reason }) => {
      setMatchStatus('idle');
      setPartner(null);
      closePeerConnection();
      let text = 'Connection lost in the dark.';
      if (reason === 'partner_skipped') {
        text = 'Your partner has vanished. Searching for a new soul...';
      } else if (reason === 'partner_disconnected') {
        text = 'Your partner has disconnected. Searching for a new soul...';
      }
      setMessages((prev) => [
        ...prev,
        { id: 'unpaired_' + Date.now(), isSystem: true, text, ts: Date.now() },
      ]);
    });

    // ── WebRTC Signaling Events ─────────────────────────
    socket.on('webrtc-offer', async ({ sdp }) => {
      try {
        if (!pcRef.current) {
          initiatePeerConnection();
        }
        await pcRef.current.setRemoteDescription(new RTCSessionDescription(sdp));
        const answer = await pcRef.current.createAnswer();
        await pcRef.current.setLocalDescription(answer);
        socketRef.current?.emit('webrtc-answer', { sdp: answer });
      } catch (err) {
        console.error("Error handling WebRTC offer:", err);
      }
    });

    socket.on('webrtc-answer', async ({ sdp }) => {
      try {
        if (pcRef.current) {
          await pcRef.current.setRemoteDescription(new RTCSessionDescription(sdp));
        }
      } catch (err) {
        console.error("Error handling WebRTC answer:", err);
      }
    });

    socket.on('webrtc-ice-candidate', async ({ candidate }) => {
      try {
        if (pcRef.current) {
          await pcRef.current.addIceCandidate(new RTCIceCandidate(candidate));
        }
      } catch (err) {
        console.error("Error adding ICE candidate:", err);
      }
    });

    socket.on('voice-state', ({ enabled }) => {
      setIsPartnerVoiceActive(enabled);
    });

    // ── Admin Events ────────────────────────────────────
    socket.on('admin-auth-success', () => {
      setIsAdmin(true);
      setAdminError(null);
    });

    socket.on('admin-auth-fail', ({ message }) => {
      setIsAdmin(false);
      setAdminError(message);
    });

    socket.on('admin-users-list', (list) => {
      setAdminUsers(list);
    });

    socket.on('admin-bans-list', (list) => {
      setAdminBans(list);
    });

    // ── Ban Event ───────────────────────────────────────
    socket.on('banned', ({ reason }) => {
      setIsBanned(true);
      setBanReason(reason);
      closePeerConnection();
      socket.disconnect();
    });

    return () => {
      closePeerConnection();
      socket.disconnect();
    };
  }, [closePeerConnection]);

  // ── WebRTC PeerConnection Initializer ──────────────────
  const initiatePeerConnection = () => {
    if (pcRef.current) return;

    const pc = new RTCPeerConnection({
      iceServers: [
        { urls: 'stun:stun.l.google.com:19302' },
        { urls: 'stun:stun1.l.google.com:19302' },
      ],
    });

    pc.onicecandidate = (event) => {
      if (event.candidate) {
        socketRef.current?.emit('webrtc-ice-candidate', { candidate: event.candidate });
      }
    };

    pc.ontrack = (event) => {
      if (event.streams && event.streams[0]) {
        setRemoteStream(event.streams[0]);
      }
    };

    if (localStreamRef.current) {
      localStreamRef.current.getTracks().forEach((track) => {
        pc.addTrack(track, localStreamRef.current);
      });
    }

    pcRef.current = pc;
  };

  // ── Voice Toggle ──────────────────────────────────────
  const toggleVoice = async () => {
    if (isVoiceActive) {
      // Turn Off
      if (localStreamRef.current) {
        localStreamRef.current.getTracks().forEach((track) => track.stop());
        localStreamRef.current = null;
        setLocalStream(null);
      }
      setIsVoiceActive(false);
      socketRef.current?.emit('voice-state', { enabled: false });

      if (pcRef.current) {
        pcRef.current.close();
        pcRef.current = null;
      }
      setRemoteStream(null);
    } else {
      // Turn On
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
        localStreamRef.current = stream;
        setLocalStream(stream);
        setIsVoiceActive(true);
        socketRef.current?.emit('voice-state', { enabled: true });

        // If partner's voice is also active, let's trigger connection
        if (isPartnerVoiceActive) {
          initiateCall();
        }
      } catch (err) {
        console.error("Failed to access microphone:", err);
        alert("Microphone access is required for voice chat.");
      }
    }
  };

  // Auto trigger WebRTC connection if partner enabled mic while we also have it enabled
  useEffect(() => {
    if (isVoiceActive && isPartnerVoiceActive && !pcRef.current && identity && partner) {
      // Lexicographical ordering on name to decide who makes the offer
      const isInitiator = identity.name < partner.name;
      if (isInitiator) {
        initiateCall();
      }
    }
  }, [isVoiceActive, isPartnerVoiceActive, identity, partner]);

  const initiateCall = async () => {
    try {
      initiatePeerConnection();
      const offer = await pcRef.current.createOffer();
      await pcRef.current.setLocalDescription(offer);
      socketRef.current?.emit('webrtc-offer', { sdp: offer });
    } catch (err) {
      console.error("Error creating WebRTC offer:", err);
    }
  };

  // ── Actions ───────────────────────────────────────────
  const sendMessage = useCallback((text, imageUrl = null) => {
    socketRef.current?.emit('send-message', { text, imageUrl });
  }, []);

  const reactToMessage = useCallback((messageId, reactionType) => {
    socketRef.current?.emit('react-message', { messageId, reactionType });
  }, []);

  const sendTypingStart = useCallback(() => {
    socketRef.current?.emit('typing-start');
  }, []);

  const sendTypingStop = useCallback(() => {
    socketRef.current?.emit('typing-stop');
  }, []);

  const reportMessage = useCallback((messageId) => {
    socketRef.current?.emit('report-message', { messageId });
  }, []);

  const switchRoom = useCallback((roomName) => {
    if (matchStatus === 'paired') return; // Cannot switch rooms while matched
    setCurrentRoom(roomName);
    setMessages([]);
    socketRef.current?.emit('switch-room', roomName);
  }, [matchStatus]);

  const joinMatchmaking = useCallback(() => {
    socketRef.current?.emit('join-matchmaking');
  }, []);

  const leaveMatchmaking = useCallback(() => {
    socketRef.current?.emit('leave-matchmaking');
  }, []);

  const skipMatch = useCallback(() => {
    socketRef.current?.emit('skip-match');
  }, []);

  const authenticateAdmin = useCallback((token) => {
    socketRef.current?.emit('admin-auth', { token });
  }, []);

  const banUser = useCallback((socketId, deviceId, ipAddress, reason) => {
    socketRef.current?.emit('admin-ban-user', { socketId, deviceId, ipAddress, reason });
  }, []);

  const unbanUser = useCallback((ipOrDeviceId) => {
    socketRef.current?.emit('admin-unban', { ipOrDeviceId });
  }, []);

  const getBans = useCallback(() => {
    socketRef.current?.emit('admin-get-bans');
  }, []);

  const socketId = socketRef.current?.id;

  return {
    connected,
    identity,
    messages,
    soulCount,
    typingUsers,
    sendMessage,
    reactToMessage,
    sendTypingStart,
    sendTypingStop,
    reportMessage,
    socketId,

    // Rooms
    currentRoom,
    switchRoom,

    // Matchmaking
    matchStatus,
    partner,
    joinMatchmaking,
    leaveMatchmaking,
    skipMatch,

    // Voice Chat
    isVoiceActive,
    isPartnerVoiceActive,
    toggleVoice,
    remoteStream,

    // Admin
    isAdmin,
    adminUsers,
    adminBans,
    adminError,
    authenticateAdmin,
    banUser,
    unbanUser,
    getBans,

    // Bans
    isBanned,
    banReason
  };
}
